"""
Represents a checker board and its state.
"""

class Board:
    def __init__(self):
        self.board = [
            [None] * 8 for _ in range(8)
        ]
        # Initialize the board with pieces
        for row in range(3, 5):
            for col in range(0, 8, 2):
                self.board[row][col] = Piece('black', (row, col))
        for row in range(6, 8):
            for col in range(1, 9, 2):
                self.board[row][col] = Piece('white', (row, col))

    def move_piece(self, start_pos, end_pos):
        piece = self.get_piece(start_pos)
        if piece:
            piece.position = end_pos
            self.board[end_pos[0]][end_pos[1]] = piece
            self.board[start_pos[0]][start_pos[1]] = None

    def get_piece(self, position):
        return self.board[position[0]][position[1]]

    def __str__(self):
        lines = []
        for row in self.board:
            line = ' | '.join('B' if p and p.color == 'black' else 'W' if p and p.color == 'white' else '.' for p in row)
            lines.append(line)
        return '\n'.join(lines)
```

